INSERT INTO TB_CHANGE_HISTORY_DETAIL (
	CHANGE_ID, SEQ, TARGET_ID, TARGET_NM, DETAIL_TYPE,
	PREV_VALUE, CURR_VALUE, REMARK
) VALUES (
	#{changeId}, #{seq}, #{targetId}, #{targetNm}, #{detailType},
	#{prevValue}, #{currValue}, #{remark}
)

mapper.select:
SELECT CHANGE_ID AS "changeId", CHANGE_TYPE AS "changeType", TARGET_TYPE AS "targetType", TARGET_ID AS "targetId", TARGET_NM AS "targetNm", CHANGE_CNT AS "changeCnt", SUMMARY AS "summary", CHANGE_USER_ID AS "changeUserId", TO_CHAR(CHANGE_DT, 'YYYY-MM-DD HH24:MI:SS') AS "changeDt" FROM TB_CHANGE_HISTORY WHERE 1=1
AND TARGET_TYPE = #{targetType}
AND CHANGE_TYPE = #{changeType}
AND CHANGE_DT >= TO_TIMESTAMP(#{fromDt}, 'YYYY-MM-DD')
AND CHANGE_DT <= TO_TIMESTAMP(#{toDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
ORDER BY CHANGE_DT DESC LIMIT 200
